    svg.append("text").attr("transform", "rotate(-90)").attr("x", -(margin.top + iH / 2)).attr("y", 14).attr("text-anchor", "middle").attr("fill", "var(--fg-muted)").style("font-size", "11px").text("Influence on pooled estimate");
