      zpcorChkTrue("n<p+4 \u2192 NaN yi", !isFinite(compute({ r: 0.5, n: 6, p: 3 }, "ZPCOR").yi));
      zpcorChkTrue("p<0  \u2192 NaN yi", !isFinite(compute({ r: 0.5, n: 50, p: -1 }, "ZPCOR").yi));
      zpcorChkTrue("n<p+4 \u2192 w=0", compute({ r: 0.5, n: 6, p: 3 }, "ZPCOR").w === 0);
