    if (!hasData) {
      panel.innerHTML = "";
      return;
    }
    function fmtZ(z) {
      return isFinite(z) ? z.toFixed(3) : "\u2014";
    }
    function fmtP2(p) {
      if (!isFinite(p)) return "\u2014";
      if (p < 1e-3) return "< 0.001";
      if (p < 0.01) return "< 0.01";
      return p.toFixed(3);
    }
